/** Formula shapes shared between the API and the client. */

export interface FormulaItem {
  colorantCode: string;
  mlPerLiter: number;
  colorantName: string;
}

export interface Formula {
  id: number;
  name: string;
  baseCode: string;
  notes: string | null;
  isPreset: boolean;
  createdAt: string;
  items: FormulaItem[];
}

/** Payload saved to localStorage while the store connection is down. */
export interface QueuedFormula {
  name: string;
  baseCode: string;
  notes: string;
  items: Array<{ colorantCode: string; mlPerLiter: number }>;
}

const QUEUE_KEY = "mixstation.offline-queue.v1";

export function loadQueue(): QueuedFormula[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = window.localStorage.getItem(QUEUE_KEY);
    if (!raw) return [];
    const parsed: unknown = JSON.parse(raw);
    if (!Array.isArray(parsed)) return [];
    return parsed.filter(
      (entry): entry is QueuedFormula =>
        typeof entry === "object" &&
        entry !== null &&
        typeof (entry as QueuedFormula).name === "string" &&
        Array.isArray((entry as QueuedFormula).items),
    );
  } catch {
    return [];
  }
}

export function persistQueue(queue: QueuedFormula[]): void {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.setItem(QUEUE_KEY, JSON.stringify(queue));
  } catch {
    // Storage may be unavailable (private mode); queuing is best-effort.
  }
}
