/**
 * Core paint-mixing domain logic.
 *
 * Rates are expressed as millilitres of colorant per litre of finished batch.
 * The base volume is reduced by the total colorant volume so the finished
 * batch matches the requested size (volume displacement is accounted for).
 */

export type VolumeUnit = "L" | "gal";

export const ML_PER_LITER = 1000;
export const ML_PER_US_GALLON = 3785.411784;
export const ML_PER_US_FLOZ = 29.5735295625;

export const MAX_BATCH_LITERS = 1000;
export const MAX_RATE_ML_PER_LITER = 600;

export interface Colorant {
  code: string;
  name: string;
  pigment: string;
  maxMlPerLiter: number;
}

export interface PaintBase {
  code: string;
  name: string;
  description: string;
  maxLoadPct: number;
}

export interface MixRowInput {
  colorantCode: string;
  mlPerLiter: number;
}

export interface MixRowResult {
  colorantCode: string;
  colorantName: string;
  pigment: string;
  mlPerLiter: number;
  totalMl: number;
  totalFloz: number;
  overMax: boolean;
}

export interface MixResult {
  unit: VolumeUnit;
  volume: number;
  targetMl: number;
  baseName: string;
  baseMl: number;
  baseFloz: number;
  totalColorantMl: number;
  loadPct: number;
  maxLoadPct: number;
  rows: MixRowResult[];
  steps: string[];
  warnings: string[];
}

/** Strict decimal parser: accepts "12", "12.5", ".5". Rejects everything else. */
export function parseDecimal(raw: string): number | null {
  const trimmed = raw.trim();
  if (!/^\d*(?:\.\d+)?$/.test(trimmed) || trimmed === "" || trimmed === ".") {
    return null;
  }
  const value = Number.parseFloat(trimmed);
  return Number.isFinite(value) ? value : null;
}

export function toMilliliters(volume: number, unit: VolumeUnit): number {
  return unit === "gal" ? volume * ML_PER_US_GALLON : volume * ML_PER_LITER;
}

export function formatMl(ml: number): string {
  const digits = ml > 0 && ml < 10 ? 1 : 0;
  return `${new Intl.NumberFormat("en-US", {
    minimumFractionDigits: digits,
    maximumFractionDigits: digits,
  }).format(ml)} ml`;
}

export function formatFloz(floz: number): string {
  return `${new Intl.NumberFormat("en-US", { maximumFractionDigits: 2 }).format(floz)} fl oz`;
}

export function formatPct(pct: number): string {
  return `${new Intl.NumberFormat("en-US", { maximumFractionDigits: 1 }).format(pct)}%`;
}

/**
 * Computes a full batch report from validated inputs.
 * Returns a `fatal` string when the batch is physically impossible
 * (colorants exceed the requested batch volume).
 */
export function computeMix(input: {
  base: PaintBase;
  rows: MixRowInput[];
  volume: number;
  unit: VolumeUnit;
  colorants: Colorant[];
}): MixResult | { fatal: string } {
  const { base, rows, volume, unit, colorants } = input;
  const targetMl = toMilliliters(volume, unit);

  const resultRows: MixRowResult[] = rows.map((row) => {
    const catalog = colorants.find((c) => c.code === row.colorantCode);
    const totalMl = row.mlPerLiter * (targetMl / ML_PER_LITER);
    return {
      colorantCode: row.colorantCode,
      colorantName: catalog?.name ?? row.colorantCode,
      pigment: catalog?.pigment ?? "—",
      mlPerLiter: row.mlPerLiter,
      totalMl,
      totalFloz: totalMl / ML_PER_US_FLOZ,
      overMax: catalog ? row.mlPerLiter > catalog.maxMlPerLiter : false,
    };
  });

  const totalColorantMl = resultRows.reduce((sum, r) => sum + r.totalMl, 0);
  const baseMl = targetMl - totalColorantMl;

  if (baseMl <= 0) {
    return {
      fatal:
        "The combined colorant volume exceeds the requested batch size. Reduce colorant rates or increase the batch volume.",
    };
  }

  const loadPct = (totalColorantMl / targetMl) * 100;

  const warnings: string[] = [];
  if (loadPct > base.maxLoadPct) {
    warnings.push(
      `Colourant load of ${formatPct(loadPct)} exceeds the recommended maximum of ${formatPct(
        base.maxLoadPct,
      )} for ${base.name}. Expect reduced hide, longer dry time and possible binder stress.`,
    );
  }
  for (const row of resultRows) {
    if (row.overMax) {
      const catalog = colorants.find((c) => c.code === row.colorantCode);
      if (catalog) {
        warnings.push(
          `${catalog.name} is dosed above its recommended maximum of ${formatMl(
            catalog.maxMlPerLiter,
          )}/L. Flooding and poor rub-out may occur.`,
        );
      }
    }
  }

  const ordered = [...resultRows].sort((a, b) => a.totalMl - b.totalMl);
  const steps: string[] = [
    `Measure ${formatMl(baseMl)} of ${base.name} into a clean mixing vessel sized for ${formatMl(
      targetMl,
    )}.`,
    ...ordered.map(
      (row) =>
        `Add ${formatMl(row.totalMl)} of ${row.colorantName} (${row.pigment}) while stirring slowly.`,
    ),
    "Stir mechanically for 2 to 3 minutes, scraping the sides and bottom of the vessel.",
    "Draw down a wet film against the reference chip and verify colour under daylight (D65) before dispensing.",
  ];

  return {
    unit,
    volume,
    targetMl,
    baseName: base.name,
    baseMl,
    baseFloz: baseMl / ML_PER_US_FLOZ,
    totalColorantMl,
    loadPct,
    maxLoadPct: base.maxLoadPct,
    rows: resultRows,
    steps,
    warnings,
  };
}

export function isFatal(result: MixResult | { fatal: string }): result is { fatal: string } {
  return "fatal" in result;
}
