/**
 * Telemetry simulation.
 *
 * No network calls are made: primary actions are logged to the console in a
 * structured format so the analytics contract can be verified in DevTools.
 */
export function logAnalytics(action: string, detail?: Record<string, unknown>): void {
  if (typeof console === "undefined") return;
  if (detail) {
    console.log(`[Analytics] User interacted with Paint Mixing Calculator — ${action}`, detail);
  } else {
    console.log(`[Analytics] User interacted with Paint Mixing Calculator — ${action}`);
  }
}
