import { IconWifi, IconWifiOff, Spinner } from "@/components/icons";

interface ConnectionBadgeProps {
  online: boolean;
  syncing: boolean;
}

/** Live connectivity indicator. Announces state changes to screen readers. */
export function ConnectionBadge({ online, syncing }: ConnectionBadgeProps) {
  const label = syncing ? "Syncing" : online ? "Online" : "Offline";
  return (
    <span
      role="status"
      aria-live="polite"
      className="flex items-center gap-2 rounded border border-ink-700 bg-ink-900 px-3 py-1.5 font-mono text-[11px] font-medium uppercase tracking-[0.12em] text-ink-200"
    >
      <span aria-hidden="true" className="relative flex h-2 w-2">
        {online && !syncing && (
          <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-success-600 opacity-60" />
        )}
        <span
          className={`relative inline-flex h-2 w-2 rounded-full ${
            online ? "bg-success-600" : "bg-danger-500"
          }`}
        />
      </span>
      {syncing ? <Spinner className="h-3 w-3" /> : online ? <IconWifi className="h-3.5 w-3.5" /> : <IconWifiOff className="h-3.5 w-3.5" />}
      {label}
    </span>
  );
}
