import {
  formatFloz,
  formatMl,
  formatPct,
  isFatal,
  type MixResult,
} from "@/lib/mixing";
import { IconAlertTriangle, IconDroplet, IconPrinter } from "@/components/icons";

interface ResultsPanelProps {
  result: MixResult | { fatal: string } | null;
  computedAt: Date | null;
}

function Stat({ label, value, sub }: { label: string; value: string; sub: string }) {
  return (
    <div className="rounded-md border border-ink-200 bg-ink-50/60 p-4">
      <p className="text-[11px] font-semibold uppercase tracking-[0.1em] text-ink-500">{label}</p>
      <p className="mt-2 font-mono text-2xl font-semibold tracking-tight text-ink-900">{value}</p>
      <p className="mt-1 text-xs text-ink-500">{sub}</p>
    </div>
  );
}

export function ResultsPanel({ result, computedAt }: ResultsPanelProps) {
  if (!result) {
    return (
      <section aria-label="Batch report" className="card no-print mt-8 p-8">
        <div className="flex flex-col items-center gap-3 rounded-md border border-dashed border-ink-300 px-6 py-10 text-center">
          <span className="grid h-12 w-12 place-items-center rounded-full bg-ink-100 text-ink-500">
            <IconDroplet className="h-6 w-6" />
          </span>
          <h3 className="font-display text-base font-bold text-ink-900">No batch calculated yet</h3>
          <p className="max-w-md text-sm leading-relaxed text-ink-500">
            Select a base paint, add colourant rates and set the batch size, then choose
            &ldquo;Calculate batch&rdquo; to produce a dispensing report.
          </p>
        </div>
      </section>
    );
  }

  if (isFatal(result)) {
    return (
      <section aria-label="Batch report" className="card no-print mt-8 p-6 sm:p-8">
        <div
          role="alert"
          className="flex items-start gap-3 rounded-md border border-danger-100 bg-danger-50 p-4"
        >
          <IconAlertTriangle className="mt-0.5 h-5 w-5 shrink-0 text-danger-600" />
          <div>
            <h3 className="font-display text-sm font-bold uppercase tracking-wide text-danger-700">
              Batch not possible
            </h3>
            <p className="mt-1 text-sm leading-relaxed text-danger-700">{result.fatal}</p>
          </div>
        </div>
      </section>
    );
  }

  const overLimit = result.loadPct > result.maxLoadPct;
  const fillWidth = Math.min(100, result.loadPct);

  return (
    <section aria-label="Batch report" className="card print-area mt-8 overflow-hidden">
      <div className="reveal">
        <div className="flex flex-wrap items-center justify-between gap-4 border-b border-ink-200 bg-ink-50/60 px-6 py-4 sm:px-8">
          <div>
            <p className="kicker">Batch report</p>
            <p className="mt-1 font-mono text-xs text-ink-500">
              Generated {computedAt ? computedAt.toLocaleString("en-GB") : "—"}
            </p>
          </div>
          <button
            type="button"
            onClick={() => window.print()}
            className="btn btn-secondary btn-sm no-print"
          >
            <IconPrinter className="h-4 w-4" />
            Print ticket
          </button>
        </div>

        <div className="space-y-8 p-6 sm:p-8">
          <div className="grid gap-3 sm:grid-cols-3">
            <Stat
              label="Batch volume"
              value={formatMl(result.targetMl)}
              sub={`${result.volume} ${result.unit === "gal" ? "US gal" : "L"} requested`}
            />
            <Stat
              label="Base required"
              value={formatMl(result.baseMl)}
              sub={result.baseName}
            />
            <Stat
              label="Colourant load"
              value={formatPct(result.loadPct)}
              sub={`Recommended max ${formatPct(result.maxLoadPct)} for ${result.baseName}`}
            />
          </div>

          <div>
            <div className="mb-2 flex items-baseline justify-between gap-4">
              <p className="text-[11px] font-semibold uppercase tracking-[0.1em] text-ink-500">
                Colourant load vs. base limit
              </p>
              <p className="font-mono text-xs text-ink-500">
                limit {formatPct(result.maxLoadPct)}
              </p>
            </div>
            <div
              role="img"
              aria-label={`Colourant load is ${formatPct(result.loadPct)} of the batch. Recommended maximum for ${result.baseName} is ${formatPct(result.maxLoadPct)}.`}
              className="relative h-3 rounded-full bg-ink-100"
            >
              <div
                className={`loadbar-fill absolute inset-y-0 left-0 rounded-full ${
                  overLimit ? "bg-danger-600 loadbar-striped" : "bg-ink-800"
                }`}
                style={{ width: `${fillWidth}%` }}
              />
              <div
                aria-hidden="true"
                className="absolute -top-1 h-5 w-0.5 rounded bg-ink-950"
                style={{ left: `${Math.min(100, result.maxLoadPct)}%` }}
              />
            </div>
          </div>

          {result.warnings.length > 0 && (
            <div className="space-y-2">
              {result.warnings.map((warning) => (
                <div
                  key={warning}
                  role="alert"
                  className="flex items-start gap-3 rounded-md border border-danger-100 bg-danger-50 p-3"
                >
                  <IconAlertTriangle className="mt-0.5 h-4 w-4 shrink-0 text-danger-600" />
                  <p className="text-[13px] leading-relaxed text-danger-700">{warning}</p>
                </div>
              ))}
            </div>
          )}

          <div className="overflow-x-auto">
            <table className="w-full min-w-[560px] border-collapse text-sm">
              <caption className="sr-only">
                Colourant additions for this batch, including rate per litre and total volumes.
              </caption>
              <thead>
                <tr className="border-b-2 border-ink-900">
                  <th scope="col" className="py-3 pr-4 text-left text-[11px] font-semibold uppercase tracking-[0.1em] text-ink-500">
                    Colourant
                  </th>
                  <th scope="col" className="py-3 pr-4 text-left text-[11px] font-semibold uppercase tracking-[0.1em] text-ink-500">
                    Pigment
                  </th>
                  <th scope="col" className="py-3 pr-4 text-right text-[11px] font-semibold uppercase tracking-[0.1em] text-ink-500">
                    Rate ml/L
                  </th>
                  <th scope="col" className="py-3 pr-4 text-right text-[11px] font-semibold uppercase tracking-[0.1em] text-ink-500">
                    Total ml
                  </th>
                  <th scope="col" className="py-3 text-right text-[11px] font-semibold uppercase tracking-[0.1em] text-ink-500">
                    Total fl oz
                  </th>
                </tr>
              </thead>
              <tbody>
                {result.rows.map((row) => (
                  <tr
                    key={row.colorantCode}
                    className="border-b border-ink-100 transition-colors hover:bg-ink-50"
                  >
                    <th scope="row" className="py-3 pr-4 text-left font-medium text-ink-900">
                      {row.colorantName}
                      <span className="ml-2 font-mono text-[11px] font-normal text-ink-400">
                        {row.colorantCode}
                      </span>
                    </th>
                    <td className="py-3 pr-4 font-mono text-xs text-ink-600">{row.pigment}</td>
                    <td className="py-3 pr-4 text-right font-mono text-ink-800">
                      {new Intl.NumberFormat("en-US", { maximumFractionDigits: 2 }).format(row.mlPerLiter)}
                    </td>
                    <td className="py-3 pr-4 text-right font-mono font-medium text-ink-900">
                      {new Intl.NumberFormat("en-US", { maximumFractionDigits: 1 }).format(row.totalMl)}
                    </td>
                    <td className="py-3 text-right font-mono text-ink-600">
                      {new Intl.NumberFormat("en-US", { maximumFractionDigits: 2 }).format(row.totalFloz)}
                    </td>
                  </tr>
                ))}
              </tbody>
              <tfoot>
                <tr className="border-b border-ink-100">
                  <th scope="row" colSpan={3} className="py-3 pr-4 text-left font-display text-xs font-bold uppercase tracking-wide text-ink-500">
                    Total colorant
                  </th>
                  <td className="py-3 pr-4 text-right font-mono font-semibold text-ink-900">
                    {new Intl.NumberFormat("en-US", { maximumFractionDigits: 1 }).format(result.totalColorantMl)}
                  </td>
                  <td className="py-3 text-right font-mono text-ink-600">
                    {new Intl.NumberFormat("en-US", { maximumFractionDigits: 2 }).format(result.totalColorantMl / 29.5735295625)}
                  </td>
                </tr>
                <tr>
                  <th scope="row" colSpan={3} className="py-3 pr-4 text-left font-display text-xs font-bold uppercase tracking-wide text-ink-500">
                    {result.baseName} (balance)
                  </th>
                  <td className="py-3 pr-4 text-right font-mono font-semibold text-ink-900">
                    {new Intl.NumberFormat("en-US", { maximumFractionDigits: 1 }).format(result.baseMl)}
                  </td>
                  <td className="py-3 text-right font-mono text-ink-600">
                    {formatFloz(result.baseFloz).replace(" fl oz", "")}
                  </td>
                </tr>
              </tfoot>
            </table>
          </div>

          <div>
            <h3 className="kicker mb-3">Mixing procedure</h3>
            <ol className="space-y-2.5">
              {result.steps.map((step, index) => (
                <li key={step} className="flex items-start gap-3">
                  <span
                    aria-hidden="true"
                    className="mt-0.5 grid h-6 w-6 shrink-0 place-items-center rounded bg-ink-900 font-mono text-[11px] font-semibold text-white"
                  >
                    {index + 1}
                  </span>
                  <p className="text-sm leading-relaxed text-ink-800">{step}</p>
                </li>
              ))}
            </ol>
          </div>
        </div>
      </div>
    </section>
  );
}
