import { Spinner, IconAlertTriangle, IconCheck, IconWifiOff } from "@/components/icons";

export type SaveStatus = "idle" | "saving" | "success" | "error";

interface SavePanelProps {
  name: string;
  notes: string;
  nameError: string | null;
  status: SaveStatus;
  statusMessage: string | null;
  online: boolean;
  queuedCount: number;
  disabled: boolean;
  onNameChange: (value: string) => void;
  onNotesChange: (value: string) => void;
  onSave: () => void;
}

export function SavePanel({
  name,
  notes,
  nameError,
  status,
  statusMessage,
  online,
  queuedCount,
  disabled,
  onNameChange,
  onNotesChange,
  onSave,
}: SavePanelProps) {
  return (
    <section aria-labelledby="save-heading" className="card no-print">
      <div className="border-b border-ink-200 px-5 py-4">
        <h2 id="save-heading" className="kicker">
          Save current mix
        </h2>
        <p className="mt-1 text-xs leading-relaxed text-ink-500">
          Stores the base, colourant rows and notes in the formula library.
        </p>
      </div>

      <div className="space-y-4 p-5">
        <div>
          <label htmlFor="formula-name" className="label">
            Formula name <span className="text-danger-600">*</span>
          </label>
          <input
            id="formula-name"
            type="text"
            autoComplete="off"
            maxLength={60}
            placeholder="e.g. Showroom Linen"
            className={`input ${nameError ? "input-invalid" : ""}`}
            value={name}
            onChange={(e) => onNameChange(e.target.value)}
            disabled={disabled}
            aria-required="true"
            aria-invalid={nameError ? true : undefined}
            aria-describedby={nameError ? "formula-name-error" : undefined}
          />
          {nameError && (
            <p id="formula-name-error" className="field-error">
              <IconAlertTriangle className="mt-px h-3 w-3 shrink-0" />
              {nameError}
            </p>
          )}
        </div>

        <div>
          <label htmlFor="formula-notes" className="label">
            Notes <span className="font-normal text-ink-400">(optional)</span>
          </label>
          <textarea
            id="formula-notes"
            rows={2}
            maxLength={240}
            placeholder="Application, sheen, customer reference…"
            className="input resize-none"
            value={notes}
            onChange={(e) => onNotesChange(e.target.value)}
            disabled={disabled}
          />
        </div>

        <button
          type="button"
          onClick={onSave}
          disabled={disabled || status === "saving"}
          className="btn btn-primary w-full"
        >
          {status === "saving" ? (
            <>
              <Spinner />
              Saving…
            </>
          ) : (
            "Save to formula library"
          )}
        </button>

        {status === "success" && statusMessage && (
          <p
            role="status"
            className="flex items-start gap-2 rounded-md border border-success-600/30 bg-success-50 p-3 text-[13px] leading-relaxed text-success-700"
          >
            <IconCheck className="mt-0.5 h-4 w-4 shrink-0 text-success-600" />
            {statusMessage}
          </p>
        )}
        {status === "error" && statusMessage && (
          <p
            role="alert"
            className="flex items-start gap-2 rounded-md border border-danger-100 bg-danger-50 p-3 text-[13px] leading-relaxed text-danger-700"
          >
            <IconAlertTriangle className="mt-0.5 h-4 w-4 shrink-0 text-danger-600" />
            {statusMessage}
          </p>
        )}

        {!online && (
          <p className="flex items-start gap-2 rounded-md border border-ink-200 bg-ink-50 p-3 text-[13px] leading-relaxed text-ink-700">
            <IconWifiOff className="mt-0.5 h-4 w-4 shrink-0 text-ink-500" />
            Connection appears to be down. Saves are queued on this device and sync
            automatically when the connection returns.
          </p>
        )}
        {queuedCount > 0 && (
          <p className="font-mono text-[11px] uppercase tracking-[0.1em] text-ink-500">
            {queuedCount} formula{queuedCount === 1 ? "" : "s"} queued offline
          </p>
        )}
      </div>
    </section>
  );
}
